const deviceSchema = z.object({
    id: z.string(),
    model: z.string().nullable(),
    config_entries: z.string().array(),
    manufacturer: z.string().nullable(),
    configuration_url: z.string().nullable().optional(),
});
const deviceListSchema = deviceSchema.array();
class DeviceCache extends Cache {
}

class DeviceRegistryManager {
    constructor(cache) {
        this._fetchedDeviceList = false;
        this._cache = cache;
    }
    async getDevice(hass, deviceID) {
        if (this._cache.has(deviceID)) {
            return this._cache.get(deviceID);
        }
        // There is currently no way to fetch a single device.
        await this._fetchDeviceList(hass);
        return this._cache.get(deviceID) ?? null;
    }
    async getMatchingDevices(hass, func) {
        await this._fetchDeviceList(hass);
        return this._cache.getMatches(func);
    }
    async _fetchDeviceList(hass) {
        if (this._fetchedDeviceList) {
            return;
        }
        let deviceList = null;
        try {
            deviceList = await homeAssistantWSRequest(hass, deviceListSchema, {
                type: 'config/device_registry/list',
            });
        }
        catch (e) {
            errorToConsole(e);
            return;
        }
        deviceList.forEach((device) => {
            this._cache.set(device.id, device);
        });
        this._fetchedDeviceList = true;
    }
}

const entitySchema = z.object({
    config_entry_id: z.string().nullable(),
    device_id: z.string().nullable(),
    disabled_by: z.string().nullable(),
    entity_id: z.string(),
    hidden_by: z.string().nullable(),
    platform: z.string(),
    translation_key: z.string().nullable(),
    // Technically the unique_id should be a string, but we want to tolerate
    // numeric unique_ids also in case they are used. See:
    // https://github.com/dermotduffy/advanced-camera-card/issues/1016
    unique_id: z.string().or(z.number()).optional(),
});
const entityListSchema = entitySchema.array();
class EntityCache extends Cache {
}

// This class manages interactions with entities, caching results and fetching
// as necessary. Some calls require every entity to be fetched, which may be
// non-trivial in size (after which they are cached forever).
class EntityRegistryManagerLive {
    constructor(cache) {
        this._fetchedEntityList = false;
        this._cache = cache;
    }
    async getEntity(hass, entityID) {
        const cachedEntity = this._cache.get(entityID);
        if (cachedEntity) {
            return cachedEntity;
        }
        let entity = null;
        try {
            entity = await homeAssistantWSRequest(hass, entitySchema, {
                type: 'config/entity_registry/get',
                entity_id: entityID,
            });
        }
        catch (e) {
            errorToConsole(e);
            return null;
        }
        this._cache.set(entity.entity_id, entity);
        return entity;
    }
    async getMatchingEntities(hass, func) {
        await this.fetchEntityList(hass);
        return this._cache.getMatches(func);
    }
    async getEntities(hass, entityIDs) {
        const output = new Map();
        const _storeEntity = async (entityID) => {
            const entity = await this.getEntity(hass, entityID);
            if (entity) {
                // When asked to fetch multiple entities, ignore missing entities (they
                // will just not feature in the output).
                output.set(entityID, entity);
            }
        };
        await Promise.all(entityIDs.map(_storeEntity));
        return output;
    }
    async fetchEntityList(hass) {
        if (this._fetchedEntityList) {
            return;
        }
        let entityList = null;
        try {
            entityList = await homeAssistantWSRequest(hass, entityListSchema, {
                type: 'config/entity_registry/list',
            });
        }
        catch (e) {
            errorToConsole(e);
            return;
        }
        entityList.forEach((entity) => {
            this._cache.set(entity.entity_id, entity);
        });
        this._fetchedEntityList = true;
    }
}

class QuickLRU extends Map {
	constructor(options = {}) {
		super();

		if (!(options.maxSize && options.maxSize > 0)) {
			throw new TypeError('`maxSize` must be a number greater than 0');
		}

		if (typeof options.maxAge === 'number' && options.maxAge === 0) {
			throw new TypeError('`maxAge` must be a number greater than 0');
		}

		// TODO: Use private class fields when ESLint supports them.
		this.maxSize = options.maxSize;
		this.maxAge = options.maxAge || Number.POSITIVE_INFINITY;
		this.onEviction = options.onEviction;
		this.cache = new Map();
		this.oldCache = new Map();
		this._size = 0;
	}

	// TODO: Use private class methods when targeting Node.js 16.
	_emitEvictions(cache) {
		if (typeof this.onEviction !== 'function') {
			return;
		}

		for (const [key, item] of cache) {
			this.onEviction(key, item.value);
		}
	}

	_deleteIfExpired(key, item) {
		if (typeof item.expiry === 'number' && item.expiry <= Date.now()) {
			if (typeof this.onEviction === 'function') {
				this.onEviction(key, item.value);
			}

			return this.delete(key);
		}

		return false;
	}

	_getOrDeleteIfExpired(key, item) {
		const deleted = this._deleteIfExpired(key, item);
		if (deleted === false) {
			return item.value;
		}
	}

	_getItemValue(key, item) {
		return item.expiry ? this._getOrDeleteIfExpired(key, item) : item.value;
	}

	_peek(key, cache) {
		const item = cache.get(key);

		return this._getItemValue(key, item);
	}

	_set(key, value) {
		this.cache.set(key, value);
		this._size++;

		if (this._size >= this.maxSize) {
			this._size = 0;
			this._emitEvictions(this.oldCache);
			this.oldCache = this.cache;
			this.cache = new Map();
		}
	}

	_moveToRecent(key, item) {
		this.oldCache.delete(key);
		this._set(key, item);
	}

	* _entriesAscending() {
		for (const item of this.oldCache) {
			const [key, value] = item;
			if (!this.cache.has(key)) {
				const deleted = this._deleteIfExpired(key, value);
				if (deleted === false) {
					yield item;
				}
			}
		}

		for (const item of this.cache) {
			const [key, value] = item;
			const deleted = this._deleteIfExpired(key, value);
			if (deleted === false) {
				yield item;
			}
		}
	}

	get(key) {
		if (this.cache.has(key)) {
			const item = this.cache.get(key);

			return this._getItemValue(key, item);
		}

		if (this.oldCache.has(key)) {
			const item = this.oldCache.get(key);
			if (this._deleteIfExpired(key, item) === false) {
				this._moveToRecent(key, item);
				return item.value;
			}
		}
	}

	set(key, value, {maxAge = this.maxAge} = {}) {
		const expiry =
			typeof maxAge === 'number' && maxAge !== Number.POSITIVE_INFINITY ?
				Date.now() + maxAge :
				undefined;
		if (this.cache.has(key)) {
			this.cache.set(key, {
				value,
				expiry
			});
		} else {
			this._set(key, {value, expiry});
		}

		return this;
	}

	has(key) {
		if (this.cache.has(key)) {
			return !this._deleteIfExpired(key, this.cache.get(key));
		}

		if (this.oldCache.has(key)) {
			return !this._deleteIfExpired(key, this.oldCache.get(key));
		}

		return false;
	}

	peek(key) {
		if (this.cache.has(key)) {
			return this._peek(key, this.cache);
		}

		if (this.oldCache.has(key)) {
			return this._peek(key, this.oldCache);
		}
	}

	delete(key) {
		const deleted = this.cache.delete(key);
		if (deleted) {
			this._size--;
		}

		return this.oldCache.delete(key) || deleted;
	}

	clear() {
		this.cache.clear();
		this.oldCache.clear();
		this._size = 0;
	}

	resize(newSize) {
		if (!(newSize && newSize > 0)) {
			throw new TypeError('`maxSize` must be a number greater than 0');
		}

		const items = [...this._entriesAscending()];
		const removeCount = items.length - newSize;
		if (removeCount < 0) {
			this.cache = new Map(items);
			this.oldCache = new Map();
			this._size = items.length;
		} else {
			if (removeCount > 0) {
				this._emitEvictions(items.slice(0, removeCount));
			}

			this.oldCache = new Map(items.slice(removeCount));
			this.cache = new Map();
			this._size = 0;
		}

		this.maxSize = newSize;
	}

	* keys() {
		for (const [key] of this) {
			yield key;
		}
	}

	* values() {
		for (const [, value] of this) {
			yield value;
		}
	}

	* [Symbol.iterator]() {
		for (const item of this.cache) {
			const [key, value] = item;
			const deleted = this._deleteIfExpired(key, value);
			if (deleted === false) {
				yield [key, value.value];
			}
		}

		for (const item of this.oldCache) {
			const [key, value] = item;
			if (!this.cache.has(key)) {
				const deleted = this._deleteIfExpired(key, value);
				if (deleted === false) {
					yield [key, value.value];
				}
			}
		}
	}

	* entriesDescending() {
		let items = [...this.cache];
		for (let i = items.length - 1; i >= 0; --i) {
			const item = items[i];
			const [key, value] = item;
			const deleted = this._deleteIfExpired(key, value);
			if (deleted === false) {
				yield [key, value.value];
			}
		}

		items = [...this.oldCache];
		for (let i = items.length - 1; i >= 0; --i) {
			const item = items[i];
			const [key, value] = item;
			if (!this.cache.has(key)) {
				const deleted = this._deleteIfExpired(key, value);
				if (deleted === false) {
					yield [key, value.value];
				}
			}
		}
	}

	* entriesAscending() {
		for (const [key, value] of this._entriesAscending()) {
			yield [key, value.value];
		}
	}

	get size() {
		if (!this._size) {
			return this.oldCache.size;
		}

		let oldCacheSize = 0;
		for (const key of this.oldCache.keys()) {
			if (!this.cache.has(key)) {
				oldCacheSize++;
			}
		}

		return Math.min(this._size + oldCacheSize, this.maxSize);
	}

	entries() {
		return this.entriesAscending();
	}

	forEach(callbackFunction, thisArgument = this) {
		for (const [key, value] of this.entriesAscending()) {
			callbackFunction.call(thisArgument, value, key, this);
		}
	}

	get [Symbol.toStringTag]() {
		return JSON.stringify([...this.entriesAscending()]);
	}
}

class LRUCache extends CacheBase {
    constructor(maxSize) {
        super(new QuickLRU({ maxSize }));
    }
}

// *************************************************************************
//                     Home Assistant API types.
// *************************************************************************
// Server side data-type defined here:
// https://github.com/home-assistant/core/blob/dev/homeassistant/components/media_source/models.py
const resolvedMediaSchema = z.object({
    url: z.string(),
    mime_type: z.string(),
});

// It's important the cache size be at least as large as the largest likely
// media query or media items will from a given query will be evicted for other
// items in the same query (which would result in only partial results being
// returned to the user).
// Note: Each entry is about 400 bytes.
const RESOLVED_MEDIA_CACHE_SIZE = 1000;
class ResolvedMediaCache extends LRUCache {
    constructor() {
        super(RESOLVED_MEDIA_CACHE_SIZE);
    }
}
/**
 * Resolve a given media source item.
 * @param hass The Home Assistant object.
 * @param mediaContentID The media content ID.
 * @param cache An optional ResolvedMediaCache object.
 * @returns The resolved media or `null`.
 */
const resolveMedia = async (hass, mediaContentID, cache) => {
    const cachedValue = cache?.get(mediaContentID) ?? null;
    if (cachedValue) {
        return cachedValue;
    }
    const request = {
        type: 'media_source/resolve_media',
        media_content_id: mediaContentID,
    };
    let resolvedMedia = null;
    try {
        resolvedMedia = await homeAssistantWSRequest(hass, resolvedMediaSchema, request);
    }
    catch (e) {
        errorToConsole(e);
    }
    if (cache && resolvedMedia) {
        cache.set(mediaContentID, resolvedMedia);
    }
    return resolvedMedia;
};

/**
 * Broadcast haptic feedback requests
 */
